/** Compute Entrypoint Contract
  *
  * guarantee manageErrorState
  * @param fanError post-state state variable
  * @param api_fanAck incoming event data port
  */
pub fn compute_spec_manageErrorState_guarantee(
  fanError: bool,
  api_fanAck: Option<TempControl_SysVerif::FanAck>) -> bool
{
  implies!(
    api_fanAck.is_some(),
    (impliesL!(
      (api_fanAck.unwrap() == TempControl_SysVerif::FanAck::Ok),
      !fanError)) &
      (impliesL!(
        (api_fanAck.unwrap() == TempControl_SysVerif::FanAck::Error),
        fanError)))
}

/** CEP-T-Guar: Top-level guarantee contracts for tct's compute entrypoint
  *
  * @param In_currentFanState pre-state state variable
  * @param In_currentSetPoint pre-state state variable
  * @param In_latestTemp pre-state state variable
  * @param currentFanState post-state state variable
  * @param currentSetPoint post-state state variable
  * @param fanError post-state state variable
  * @param latestTemp post-state state variable
  * @param api_currentTemp incoming event data port
  * @param api_fanAck incoming event data port
  * @param api_setPoint incoming event data port
  * @param api_fanCmd outgoing event data port
  */
pub fn compute_CEP_T_Guar(
  In_currentFanState: TempControl_SysVerif::FanCmd,
  In_currentSetPoint: TempControl_SysVerif::SetPoint,
  In_latestTemp: TempControl_SysVerif::Temperature,
  currentFanState: TempControl_SysVerif::FanCmd,
  currentSetPoint: TempControl_SysVerif::SetPoint,
  fanError: bool,
  latestTemp: TempControl_SysVerif::Temperature,
  api_currentTemp: Option<TempControl_SysVerif::Temperature>,
  api_fanAck: Option<TempControl_SysVerif::FanAck>,
  api_setPoint: Option<TempControl_SysVerif::SetPoint>,
  api_fanCmd: Option<TempControl_SysVerif::FanCmd>) -> bool
{
  let r0: bool = compute_spec_errorState_guarantee(In_currentFanState, currentFanState, fanError, api_fanCmd);
  let r1: bool = compute_spec_TC_Req_01_guarantee(currentFanState, currentSetPoint, fanError, latestTemp);
  let r2: bool = compute_spec_TC_Req_02_guarantee(currentFanState, currentSetPoint, fanError, latestTemp);
  let r3: bool = compute_spec_TC_Req_03_guarantee(In_currentFanState, currentFanState, currentSetPoint, fanError, latestTemp);
  let r4: bool = compute_spec_mustSendFanCmd_guarantee(In_currentFanState, currentFanState, fanError, api_fanCmd);
  let r5: bool = compute_spec_setPointChanged_guarantee(currentSetPoint, api_setPoint);
  let r6: bool = compute_spec_fanAck_setPointNotModified_guarantee(In_currentSetPoint, currentSetPoint, api_fanAck, api_setPoint);
  let r7: bool = compute_spec_currentTemp_setPointNotModified_guarantee(In_currentSetPoint, currentSetPoint, api_currentTemp, api_setPoint);
  let r8: bool = compute_spec_tempChanged_guarantee(latestTemp, api_currentTemp);
  let r9: bool = compute_spec_setPoint_latestTempNotModified_guarantee(In_latestTemp, latestTemp, api_currentTemp, api_setPoint);
  let r10: bool = compute_spec_fanAck_latestTempNotModified_guarantee(In_latestTemp, latestTemp, api_currentTemp, api_fanAck);
  let r11: bool = compute_spec_manageErrorState_guarantee(fanError, api_fanAck);

  return r0 && r1 && r2 && r3 && r4 && r5 && r6 && r7 && r8 && r9 && r10 && r11;
}

/** CEP-Post: Compute Entrypoint Post-Condition for tct
  *
  * @param In_currentFanState pre-state state variable
  * @param In_currentSetPoint pre-state state variable
  * @param In_fanError pre-state state variable
  * @param In_latestTemp pre-state state variable
  * @param currentFanState post-state state variable
  * @param currentSetPoint post-state state variable
  * @param fanError post-state state variable
  * @param latestTemp post-state state variable
  * @param api_currentTemp incoming event data port
  * @param api_fanAck incoming event data port
  * @param api_setPoint incoming event data port
  * @param api_fanCmd outgoing event data port
  */
pub fn compute_CEP_Post(
  In_currentFanState: TempControl_SysVerif::FanCmd,
  In_currentSetPoint: TempControl_SysVerif::SetPoint,
  In_fanError: bool,
  In_latestTemp: TempControl_SysVerif::Temperature,
  currentFanState: TempControl_SysVerif::FanCmd,
  currentSetPoint: TempControl_SysVerif::SetPoint,
  fanError: bool,
  latestTemp: TempControl_SysVerif::Temperature,
  api_currentTemp: Option<TempControl_SysVerif::Temperature>,
  api_fanAck: Option<TempControl_SysVerif::FanAck>,
  api_setPoint: Option<TempControl_SysVerif::SetPoint>,
  api_fanCmd: Option<TempControl_SysVerif::FanCmd>) -> bool
{
  // CEP-Guar: guarantee clauses of tct's compute entrypoint
  let r0: bool = compute_CEP_T_Guar(In_currentFanState, In_currentSetPoint, In_latestTemp, currentFanState, currentSetPoint, fanError, latestTemp, api_currentTemp, api_fanAck, api_setPoint, api_fanCmd);

  return r0;
}
